 {"id":"bd-197","title":"Implement RichErrorRenderer for styled error display","description":"## Purpose and Rationale

Create a sophisticated error rendering system that displays errors with full context, suggestions, and visual hierarchy using rich_rust. Errors should be informative, not scary - they should guide users toward solutions.

## Background

Error display is where many CLI tools fail - they show cryptic messages that leave users confused. The RichErrorRenderer transforms FastMCP errors into beautiful, actionable displays with:
- Clear error categorization
- Contextual information
- Suggested fixes
- Stack traces (when appropriate)
- Links to documentation

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/error/renderer.rs

use rich_rust::{Panel, Style, Color, Rule};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::error::Error;

/// Renders errors in a beautiful, informative format
pub struct RichErrorRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
    show_suggestions: bool,
    show_backtrace: bool,
    show_error_code: bool,
}

impl RichErrorRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            theme,
            context,
            show_suggestions: true,
            show_backtrace: std::env::var("RUST_BACKTRACE").is_ok(),
            show_error_code: true,
        }
    }

    /// Render an error with full context
    pub fn render(&self, error: &Error, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(error, console);
            return;
        }

        // Error header
        let category = self.categorize_error(error);
        self.render_header(category, console);

        // Main error panel
        self.render_error_panel(error, console);

        // Suggestions
        if self.show_suggestions {
            if let Some(suggestions) = self.get_suggestions(error) {
                self.render_suggestions(&suggestions, console);
            }
        }

        // Context/backtrace
        if self.show_backtrace {
            self.render_context(error, console);
        }
    }

    fn categorize_error(&self, error: &Error) -> ErrorCategory {
        match error {
            Error::Transport(_) => ErrorCategory::Connection,
            Error::Protocol(_) => ErrorCategory::Protocol,
            Error::Handler(_) => ErrorCategory::Handler,
            Error::Timeout(_) => ErrorCategory::Timeout,
            Error::Cancelled => ErrorCategory::Cancelled,
            Error::Internal(_) => ErrorCategory::Internal,
            _ => ErrorCategory::Unknown,
        }
    }

    fn render_header(&self, category: ErrorCategory, console: &FastMcpConsole) {
        let (icon, label, style) = match category {
            ErrorCategory::Connection => ("🔌", "Connection Error", self.theme.error_style()),
            ErrorCategory::Protocol => ("📋", "Protocol Error", self.theme.error_style()),
            ErrorCategory::Handler => ("⚙️", "Handler Error", self.theme.warning_style()),
            ErrorCategory::Timeout => ("⏱️", "Timeout", self.theme.warning_style()),
            ErrorCategory::Cancelled => ("✋", "Cancelled", self.theme.info_style()),
            ErrorCategory::Internal => ("💥", "Internal Error", self.theme.error_style()),
            ErrorCategory::Unknown => ("❌", "Error", self.theme.error_style()),
        };

        let rule = Rule::with_title(&format!("{} {}", icon, label))
            .style(style);
        console.print_renderable(&rule);
    }

    fn render_error_panel(&self, error: &Error, console: &FastMcpConsole) {
        let message = error.to_string();
        let code = self.error_code(error);

        let content = if self.show_error_code {
            format!("[bold]{}[/]\n\n{}", code, message)
        } else {
            message
        };

        let panel = Panel::from_text(&content)
            .style(self.theme.error_border_style())
            .padding(1);

        console.print_renderable(&panel);
    }

    fn render_suggestions(&self, suggestions: &[String], console: &FastMcpConsole) {
        console.print("\n[bold cyan]💡 Suggestions:[/]");
        for (i, suggestion) in suggestions.iter().enumerate() {
            console.print(&format!("  [dim]{}.[/] {}", i + 1, suggestion));
        }
    }

    fn get_suggestions(&self, error: &Error) -> Option<Vec<String>> {
        match error {
            Error::Transport(msg) if msg.contains("connection refused") => {
                Some(vec![
                    "Check that the MCP client is running".to_string(),
                    "Verify the transport configuration".to_string(),
                    "Check firewall settings".to_string(),
                ])
            }
            Error::Protocol(msg) if msg.contains("unknown method") => {
                Some(vec![
                    "Verify the method name is correct".to_string(),
                    "Check that the handler is registered".to_string(),
                    "Run with RUST_LOG=debug for more details".to_string(),
                ])
            }
            Error::Timeout(_) => {
                Some(vec![
                    "Increase the timeout value in configuration".to_string(),
                    "Check for slow operations in handlers".to_string(),
                    "Consider using async operations".to_string(),
                ])
            }
            _ => None,
        }
    }

    fn error_code(&self, error: &Error) -> String {
        match error {
            Error::Transport(_) => "E001".to_string(),
            Error::Protocol(_) => "E002".to_string(),
            Error::Handler(_) => "E003".to_string(),
            Error::Timeout(_) => "E004".to_string(),
            Error::Cancelled => "E005".to_string(),
            Error::Internal(_) => "E500".to_string(),
            _ => "E000".to_string(),
        }
    }

    fn render_plain(&self, error: &Error, console: &FastMcpConsole) {
        console.print(&format!("ERROR: {}", error));
    }
}

#[derive(Debug, Clone, Copy)]
enum ErrorCategory {
    Connection,
    Protocol,
    Handler,
    Timeout,
    Cancelled,
    Internal,
    Unknown,
}
```

